window.docContents[250].resolve({"/Analytic-Number-Theory/The-Wiener___Ikehara-theorem-and-the-Prime-Number-Theorem/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Analytic-Number-Theory--The-Wiener___Ikehara-theorem-and-the-Prime-Number-Theorem":{"contents":"The EulerProducts project of Michael Stoll develops Euler products in general and derives the Prime\nNumber Theorem and Dirichlet's theorem from a clean statement of the Wiener–Ikehara Tauberian theorem,\nwhich is taken as a hypothesis (the Tauberian theorem itself is proved analytically in\nPrimeNumberTheoremAnd). The nodes below are informal; each links to its exact source declaration at\ncommit 7376f1a and connects into the dependency graph through the mathlib-backed nodes above.\n\n\n\n\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Analytic Number Theory","header":"2.9. The Wiener–Ikehara theorem and the Prime Number Theorem","id":"/Analytic-Number-Theory/The-Wiener___Ikehara-theorem-and-the-Prime-Number-Theorem/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Analytic-Number-Theory--The-Wiener___Ikehara-theorem-and-the-Prime-Number-Theorem"},"/Elliptic-Curves-and-Arithmetic-Geometry/The-Weil-conjectures-and-the-Hasse___Weil-zeta-function/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--The-Weil-conjectures-and-the-Hasse___Weil-zeta-function":{"contents":"\n\n\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Elliptic Curves and Arithmetic Geometry","header":"7.12. The Weil conjectures and the Hasse–Weil zeta function","id":"/Elliptic-Curves-and-Arithmetic-Geometry/The-Weil-conjectures-and-the-Hasse___Weil-zeta-function/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--The-Weil-conjectures-and-the-Hasse___Weil-zeta-function"}});